const TEAM = ["Norah","Abeer","Dina","Aisha","Shahd","Rahaf","Zaha","Joud","Other / Trainee"];

const IL = {ni:"No Image",ns:"No SEO Title",nd:"No SEO Desc",nb:"No Body",
            tl:"Title >60",ts:"Title <30",dup:"Duplicate",cb:"Corrupt HTML"};
const IC = {ni:"c",ns:"c",nd:"c",cb:"c",nb:"w",tl:"w",dup:"w",ts:"i"};

const TODAY = new Date().toISOString().slice(0,10);
const WEEK_START = (() => {
  const d = new Date(); d.setDate(d.getDate() - d.getDay());
  return d.toISOString().slice(0,10);
})();

const ADMIN = "https://admin.shopify.com/store/alrugaib-furniture/products/";
const SITE  = "https://www.alrugaibfurniture.com/products/";

// ── storage ─────────────────────────────────────────────────────────────────
function loadLogs() {
  try { return JSON.parse(localStorage.getItem("seo_logs_v4") || "[]"); }
  catch { return []; }
}
function saveLogs(logs) {
  try { localStorage.setItem("seo_logs_v4", JSON.stringify(logs.slice(-500))); } catch {}
}
async function syncLogs(logs) {
  try { await window.storage.set("seo_logs_v4", JSON.stringify(logs.slice(-500))); } catch {}
}
async function loadRemote() {
  try {
    const r = await window.storage.get("seo_logs_v4");
    return r ? JSON.parse(r.value) : [];
  } catch { return []; }
}

// ── helpers ──────────────────────────────────────────────────────────────────
function getVendor(name) {
  return VENDOR_DATA.find(v => v.v === name) || { v: name, n: 0, tot: 0, p: [] };
}
function exportCSV(vendor, products) {
  const hdr = ["Handle","Title","Type","Issues","NEW SEO Title (max 60)","NEW SEO Desc (max 160)","NEW Body","Store URL","Admin URL"];
  const rows = [hdr.join(",")];
  products.forEach(p => {
    const issues = p.i.map(i => IL[i]||i).join("; ");
    rows.push([
      `"${p.h}"`,
      `"${p.t.replace(/"/g,"''")}"`,
      `"${p.pt}"`,
      `"${issues}"`,
      '""','""','""',
      `"${SITE}${p.h}"`,
      `"${ADMIN}${p.h}"`
    ].join(","));
  });
  const blob = new Blob([rows.join("\n")],{type:"text/csv"});
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `seo_${vendor.replace(/\s+/g,"_")}_${TODAY}.csv`;
  a.click();
}
function sevLabel(s) {
  if (s >= 25) return { t:"Critical", bg:"#C0392B" };
  if (s >= 15) return { t:"High",     bg:"#D97706" };
  return              { t:"Medium",   bg:"#444"    };
}

// ── app ──────────────────────────────────────────────────────────────────────
function TrackerApp() {
  const [logs, setLogs]       = useState([]);
  const [user, setUser]       = useState("");
  const [view, setView]       = useState("login"); // login | work | manager
  const [ready, setReady]     = useState(false);

  useEffect(() => {
    const local = loadLogs();
    setLogs(local);
    loadRemote().then(remote => {
      const seen = new Set(local.map(l => l.id));
      const merged = [...local, ...remote.filter(l => !seen.has(l.id))];
      merged.sort((a,b) => b.ts - a.ts);
      setLogs(merged);
      saveLogs(merged);
    }).finally(() => setReady(true));
  }, []);

  function addLog(vendor) {
    const log = { id:`${user}_${vendor}_${Date.now()}`, user, vendor, date: TODAY, ts: Date.now() };
    const next = [log, ...logs];
    setLogs(next);
    saveLogs(next);
    syncLogs(next);
  }

  function logout() { setUser(""); setView("login"); }

  if (!ready) return (
    <div style={S.page}>
      <div style={{color:"#555",textAlign:"center",paddingTop:80,fontSize:13}}>Loading...</div>
    </div>
  );

  if (view === "login") return (
    <Login
      user={user} setUser={setUser}
      onStart={() => setView(user === "Haitham (Manager)" ? "manager" : "work")}
      onManager={() => setView("manager")}
    />
  );
  if (view === "manager") return (
    <Manager logs={logs} onBack={logout} />
  );
  return (
    <Work user={user} logs={logs} addLog={addLog} onLogout={logout} onManager={() => setView("manager")} />
  );
}

// ── login ─────────────────────────────────────────────────────────────────────
function Login({ user, setUser, onStart, onManager }) {
  return (
    <div style={S.page}>
      <div style={{maxWidth:420,margin:"0 auto",padding:"80px 24px"}}>
        <div style={{color:"#D4AF37",fontSize:22,fontWeight:700,marginBottom:4}}>Al Rugaib</div>
        <div style={{fontSize:22,fontWeight:700,letterSpacing:"-0.5px",marginBottom:6}}>SEO Content Tracker</div>
        <div style={{fontSize:13,color:"#555",marginBottom:28,lineHeight:1.6}}>
          Select your name to view your priority list and log daily work.
        </div>
        <div style={{marginBottom:16}}>
          <div style={S.label}>WHO ARE YOU?</div>
          <select style={S.select} value={user} onChange={e => setUser(e.target.value)}>
            <option value="">-- Select name --</option>
            {TEAM.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <button
          style={{...S.btnPrimary, opacity: user ? 1 : 0.4, cursor: user ? "pointer" : "default"}}
          onClick={() => { if (user) onStart(); }}
        >
          {user === "Haitham (Manager)" ? "Open Manager View →" : "Start Working →"}
        </button>
        <div style={{marginTop:14,textAlign:"center"}}>
          <span style={{fontSize:11,color:"#444",cursor:"pointer"}} onClick={onManager}>
            Manager Report
          </span>
        </div>
      </div>
    </div>
  );
}

// ── work flow ─────────────────────────────────────────────────────────────────
function Work({ user, logs, addLog, onLogout, onManager }) {
  const [step, setStep]           = useState("brand"); // brand | list | done
  const [vendor, setVendor]       = useState("");
  const [customV, setCustomV]     = useState("");
  const [showCustom, setShowCustom] = useState(false);
  const [search, setSearch]       = useState("");
  const [filterIssue, setFilterIssue] = useState("");
  const [page, setPage]           = useState(0);
  const [exported, setExported]   = useState(false);
  const [marked, setMarked]       = useState(false);
  const [selected, setSelected]   = useState([]);
  const PAGE = 50;

  const vd = getVendor(vendor);
  const myLogs = logs.filter(l => l.user === user && l.vendor === vendor);
  const todayLogged = myLogs.some(l => l.date === TODAY);
  const allVendorLogs = logs.filter(l => l.vendor === vendor);

  function doMark() {
    addLog(vendor);
    setMarked(true);
    setStep("done");
  }

  function doExport() {
    let prods = vd.p;
    if (filterIssue) prods = prods.filter(p => p.i.includes(filterIssue));
    if (search) prods = prods.filter(p => p.t.toLowerCase().includes(search.toLowerCase()));
    exportCSV(vendor, prods.length > 0 ? prods : vd.p);
    setExported(true);
  }

  function doExportSelected() {
    const sel = vd.p.filter(p => selected.includes(p.h));
    if (sel.length === 0) return;
    exportCSV(vendor, sel);
  }

  function toggleSelect(handle) {
    setSelected(prev =>
      prev.includes(handle) ? prev.filter(h => h !== handle) : [...prev, handle]
    );
  }

  function toggleAll(handles) {
    const allSelected = handles.every(h => selected.includes(h));
    if (allSelected) {
      setSelected(prev => prev.filter(h => !handles.includes(h)));
    } else {
      setSelected(prev => [...new Set([...prev, ...handles])]);
    }
  }

  // BRAND SELECTION
  if (step === "brand") {
    const vendorsWithIssues = VENDOR_DATA.filter(v => v.n > 0);
    return (
      <div style={S.page}>
        <Bar user={user} onLogout={onLogout} onManager={onManager} />
        <div style={S.main}>
          <div style={{marginBottom:20}}>
            <div style={S.h2}>Select Brand to Work On</div>
            <div style={S.sub}>Pick any vendor. Multiple team members can work the same brand simultaneously.</div>
          </div>

          {showCustom && (
            <div style={{display:"flex",gap:8,marginBottom:16}}>
              <input
                style={{...S.input,flex:1}}
                placeholder="Type brand name..."
                value={customV}
                autoFocus
                onChange={e => setCustomV(e.target.value)}
                onKeyDown={e => { if (e.key==="Enter" && customV.trim()) { setVendor(customV.trim()); setShowCustom(false); }}}
              />
              <button style={S.btnSec} onClick={() => { if(customV.trim()) { setVendor(customV.trim()); setShowCustom(false); }}}>Use →</button>
              <button style={S.btnSec} onClick={() => setShowCustom(false)}>Cancel</button>
            </div>
          )}

          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:10,marginBottom:20}}>
            {vendorsWithIssues.map(v => {
              const vLogs = logs.filter(l => l.vendor === v.v);
              const todayCount = vLogs.filter(l => l.date === TODAY).length;
              const sel = vendor === v.v;
              return (
                <div key={v.v}
                  style={{...S.card,...(sel?{borderColor:"#D4AF37",background:"rgba(212,175,55,0.05)"}:{})}}
                  onClick={() => setVendor(v.v)}>
                  <div style={{fontWeight:700,fontSize:13,marginBottom:3}}>{v.v}</div>
                  <div style={{fontSize:11,color:"#C0392B"}}>{v.n.toLocaleString()} products need SEO</div>
                  <div style={{fontSize:10,color:"#444",marginTop:2}}>
                    {v.tot.toLocaleString()} active total
                    {todayCount > 0 && <span style={{color:"#4ade80"}}> · {todayCount} check-in{todayCount>1?"s":""} today</span>}
                  </div>
                </div>
              );
            })}
            <div
              style={{...S.card,border:"1px dashed #333",color:"#555",cursor:"pointer"}}
              onClick={() => { setShowCustom(true); setVendor(""); }}>
              <div style={{fontSize:13}}>+ Other brand...</div>
            </div>
          </div>

          <button
            style={{...S.btnPrimary,width:"auto",padding:"10px 28px",opacity:vendor?1:0.4,cursor:vendor?"pointer":"default"}}
            onClick={() => { if (vendor) setStep("list"); }}>
            See Priority List →
          </button>
        </div>
      </div>
    );
  }

  // PRIORITY LIST
  if (step === "list") {
    let prods = [...vd.p];
    if (filterIssue) prods = prods.filter(p => p.i.includes(filterIssue));
    if (search) prods = prods.filter(p => p.t.toLowerCase().includes(search.toLowerCase()));
    const total = prods.length;
    const pageProds = prods.slice(page * PAGE, (page+1)*PAGE);
    const totalPages = Math.ceil(total / PAGE);
    const teamTodayBrands = [...new Set(allVendorLogs.filter(l=>l.date===TODAY).map(l=>l.user))];

    return (
      <div style={S.page}>
        <Bar user={user} vendor={vendor} onLogout={onLogout} onManager={onManager} />
        <div style={S.main}>

          {/* Status */}
          <div style={{...S.card,display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10,marginBottom:16,padding:"14px 18px"}}>
            <div>
              <div style={{fontWeight:700,fontSize:15}}>{vendor}</div>
              <div style={{fontSize:12,color:"#666",marginTop:2}}>
                {vd.n.toLocaleString()} products need SEO
                {teamTodayBrands.length > 0 && (
                  <span style={{color:"#4ade80"}}> · Worked today: {teamTodayBrands.join(", ")}</span>
                )}
              </div>
            </div>
            <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
              {selected.length > 0 && (
                <button style={{...S.btnAlt,borderColor:"#D4AF37",color:"#D4AF37"}} onClick={doExportSelected}>
                  ↓ Export Selected ({selected.length})
                </button>
              )}
              <button style={S.btnAlt} onClick={doExport}>
                ↓ Export All{exported ? " ✓" : ""}
              </button>
              {todayLogged ? (
                <div style={{...S.btnPrimary,width:"auto",padding:"8px 16px",fontSize:12,background:"#16A34A",cursor:"default"}}>
                  ✓ Logged Today
                </div>
              ) : (
                <button style={{...S.btnPrimary,width:"auto",padding:"8px 16px",fontSize:12}} onClick={doMark}>
                  ✓ Mark Day Complete
                </button>
              )}
            </div>
          </div>

          {/* My check-in history */}
          {myLogs.length > 0 && (
            <div style={{background:"#0d0d0d",border:"1px solid #1a1a1a",borderRadius:2,padding:"10px 14px",marginBottom:14}}>
              <div style={{fontSize:10,color:"#444",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:6}}>
                Your check-ins on {vendor}
              </div>
              <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
                {myLogs.slice(0,15).map(l => (
                  <span key={l.id} style={{background:"rgba(212,175,55,0.1)",color:"#D4AF37",fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:20}}>
                    {l.date}
                  </span>
                ))}
              </div>
            </div>
          )}

          {/* Filters */}
          <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap",alignItems:"center"}}>
            <input
              style={{...S.input,width:180,padding:"6px 10px",fontSize:12}}
              placeholder="Search product..."
              value={search}
              onChange={e => { setSearch(e.target.value); setPage(0); }}
            />
            <select style={{...S.select,width:"auto",padding:"6px 10px",fontSize:12}}
              value={filterIssue}
              onChange={e => { setFilterIssue(e.target.value); setPage(0); }}>
              <option value="">All Issues</option>
              <option value="ns">Missing SEO Title</option>
              <option value="nd">Missing SEO Desc</option>
              <option value="ni">Missing Image</option>
              <option value="nb">Missing Body</option>
              <option value="tl">Title Too Long</option>
              <option value="dup">Duplicate Title</option>
            </select>
            <span style={{fontSize:11,background:"rgba(212,175,55,0.1)",color:"#D4AF37",padding:"5px 12px",borderRadius:20}}>
              {total.toLocaleString()} products
            </span>
          </div>

          {/* Table */}
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead>
                <tr>
                  <th style={{background:"#0d0d0d",padding:"8px 10px",width:32}}>
                    <input
                      type="checkbox"
                      style={{accentColor:"#D4AF37",cursor:"pointer"}}
                      checked={pageProds.length > 0 && pageProds.every(p => selected.includes(p.h))}
                      onChange={() => toggleAll(pageProds.map(p => p.h))}
                    />
                  </th>
                  {["Product","Type","Severity","Issues","View"].map(h => (
                    <th key={h} style={{background:"#0d0d0d",padding:"8px 12px",textAlign:"left",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.5px",color:"#555",borderBottom:"1px solid #1a1a1a",whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {pageProds.map(p => {
                  const sev = sevLabel(p.s);
                  const isSel = selected.includes(p.h);
                  return (
                    <tr key={p.h} style={{borderBottom:"1px solid #111", background: isSel ? "rgba(212,175,55,0.04)" : "transparent"}}>
                      <td style={{padding:"9px 10px"}}>
                        <input
                          type="checkbox"
                          style={{accentColor:"#D4AF37",cursor:"pointer"}}
                          checked={isSel}
                          onChange={() => toggleSelect(p.h)}
                        />
                      </td>
                      <td style={{padding:"9px 12px",maxWidth:220}}>
                        <div style={{fontWeight:600,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{p.t}</div>
                      </td>
                      <td style={{padding:"9px 12px",color:"#555",whiteSpace:"nowrap",fontSize:11}}>{p.pt}</td>
                      <td style={{padding:"9px 12px"}}>
                        <span style={{background:sev.bg,color:"#fff",fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:2}}>{sev.t}</span>
                      </td>
                      <td style={{padding:"9px 12px"}}>
                        <div style={{display:"flex",flexWrap:"wrap",gap:3}}>
                          {p.i.map(i => (
                            <span key={i} style={{
                              background: IC[i]==="c"?"rgba(192,57,43,0.15)":IC[i]==="w"?"rgba(215,119,6,0.15)":"rgba(29,78,216,0.15)",
                              color: IC[i]==="c"?"#C0392B":IC[i]==="w"?"#D97706":"#60A5FA",
                              fontSize:9,fontWeight:700,padding:"2px 5px",borderRadius:2,textTransform:"uppercase"
                            }}>{IL[i]||i}</span>
                          ))}
                        </div>
                      </td>
                      <td style={{padding:"9px 12px",whiteSpace:"nowrap"}}>
                        <a href={`${SITE}${p.h}`} target="_blank" rel="noreferrer"
                          style={{color:"#D4AF37",textDecoration:"none",fontWeight:700,fontSize:11}}>
                          View ↗
                        </a>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 0",fontSize:12,color:"#555"}}>
            <span>Showing {page*PAGE+1}–{Math.min((page+1)*PAGE,total)} of {total.toLocaleString()}</span>
            <div style={{display:"flex",gap:4}}>
              <button style={S.pb} onClick={() => setPage(p=>Math.max(0,p-1))} disabled={page===0}>← Prev</button>
              {Array.from({length:Math.min(5,totalPages)},(_,i)=>{
                const pg = Math.max(0,page-2)+i;
                if (pg >= totalPages) return null;
                return <button key={pg} style={{...S.pb,...(pg===page?{background:"#D4AF37",color:"#000",borderColor:"#D4AF37"}:{})}} onClick={() => setPage(pg)}>{pg+1}</button>;
              })}
              <button style={S.pb} onClick={() => setPage(p=>Math.min(totalPages-1,p+1))} disabled={page>=totalPages-1}>Next →</button>
            </div>
          </div>

          <div style={{display:"flex",gap:10,marginTop:8}}>
            <button style={S.btnSec} onClick={() => { setStep("brand"); setVendor(""); setSearch(""); setFilterIssue(""); setPage(0); setSelected([]); }}>← Change Brand</button>
          </div>
        </div>
      </div>
    );
  }

  // DONE
  return (
    <div style={S.page}>
      <Bar user={user} onLogout={onLogout} onManager={onManager} />
      <div style={{...S.main,textAlign:"center",paddingTop:60}}>
        <div style={{fontSize:52,marginBottom:8}}>✓</div>
        <div style={{fontSize:20,fontWeight:700,marginBottom:6}}>Day Logged</div>
        <div style={{fontSize:13,color:"#555",marginBottom:32}}>{TODAY} · {vendor} · {user}</div>
        <div style={{display:"flex",gap:10,justifyContent:"center",flexWrap:"wrap"}}>
          <button style={{...S.btnPrimary,width:"auto",padding:"10px 24px"}}
            onClick={() => { setStep("brand"); setVendor(""); setExported(false); setMarked(false); }}>
            Work on Another Brand
          </button>
          <button style={S.btnSec} onClick={() => setStep("list")}>Back to List</button>
          <button style={S.btnSec} onClick={onManager}>Manager View</button>
        </div>
      </div>
    </div>
  );
}

// ── manager ───────────────────────────────────────────────────────────────────
function Manager({ logs, onBack }) {
  const todayLogs = logs.filter(l => l.date === TODAY);
  const weekLogs  = logs.filter(l => l.date >= WEEK_START);

  const kpis = [
    { label:"Check-ins Today",      val: todayLogs.length,                                    color:"#D4AF37" },
    { label:"Active Members Today",  val: new Set(todayLogs.map(l=>l.user)).size,              color:"#4ade80" },
    { label:"Brands Touched Today",  val: new Set(todayLogs.map(l=>l.vendor)).size,            color:"#60A5FA" },
    { label:"Check-ins This Week",   val: weekLogs.length,                                     color:"#C084FC" },
  ];

  const members = TEAM.filter(t => t !== "Haitham (Manager)").map(m => {
    const ml = logs.filter(l => l.user === m);
    const today = ml.filter(l => l.date === TODAY);
    const week  = ml.filter(l => l.date >= WEEK_START);
    return {
      name: m,
      todayBrands: [...new Set(today.map(l=>l.vendor))],
      weekCount: week.length,
      totalCount: ml.length,
    };
  });

  const brandRows = VENDOR_DATA.filter(v=>v.n>0).map(v => {
    const vl = logs.filter(l => l.vendor === v.v);
    const todayWorkers = [...new Set(vl.filter(l=>l.date===TODAY).map(l=>l.user))];
    const weekCount = vl.filter(l=>l.date>=WEEK_START).length;
    return { vendor: v.v, issues: v.n, total: v.tot, todayWorkers, weekCount };
  });

  const feed = [...logs].sort((a,b)=>b.ts-a.ts).slice(0,25);

  return (
    <div style={S.page}>
      <div style={{background:"#000",borderBottom:"1px solid #1a1a1a",padding:"0 24px",height:52,display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:100}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <span style={{color:"#D4AF37",fontWeight:700,fontSize:15}}>Al Rugaib</span>
          <span style={{width:1,height:14,background:"#333"}}/>
          <span style={{fontSize:11,color:"#555",textTransform:"uppercase",letterSpacing:1}}>Manager Dashboard</span>
        </div>
        <button style={S.btnSec} onClick={onBack}>← Back</button>
      </div>
      <div style={S.main}>

        {/* KPIs */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>
          {kpis.map(k => (
            <div key={k.label} style={S.card}>
              <div style={{fontSize:10,color:"#555",textTransform:"uppercase",letterSpacing:"0.8px",marginBottom:6}}>{k.label}</div>
              <div style={{fontSize:32,fontWeight:700,color:k.color}}>{k.val}</div>
            </div>
          ))}
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:20}}>

          {/* Team */}
          <div style={S.card}>
            <div style={{fontSize:11,color:"#555",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:14}}>Team — Today</div>
            {members.map(m => (
              <div key={m.name} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid #1a1a1a"}}>
                <div>
                  <div style={{fontWeight:600,fontSize:13}}>{m.name}</div>
                  <div style={{fontSize:11,color:"#555",marginTop:2}}>
                    {m.todayBrands.length > 0
                      ? m.todayBrands.join(", ")
                      : <span style={{color:"#333"}}>No activity today</span>}
                  </div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontSize:18,fontWeight:700,color:m.todayBrands.length>0?"#4ade80":"#333"}}>
                    {m.todayBrands.length}
                  </div>
                  <div style={{fontSize:10,color:"#444"}}>brands</div>
                </div>
              </div>
            ))}
          </div>

          {/* Feed */}
          <div style={S.card}>
            <div style={{fontSize:11,color:"#555",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:14}}>Activity Feed</div>
            {feed.length === 0
              ? <div style={{fontSize:12,color:"#333"}}>No activity yet.</div>
              : feed.map(l => (
                <div key={l.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"7px 0",borderBottom:"1px solid #111"}}>
                  <div>
                    <span style={{fontWeight:600,fontSize:12,color:"#D4AF37"}}>{l.user.split(" ")[0]}</span>
                    <span style={{fontSize:12,color:"#888"}}> worked on </span>
                    <span style={{fontSize:12,color:"#aaa"}}>{l.vendor}</span>
                  </div>
                  <div style={{fontSize:10,color:"#444",flexShrink:0,marginLeft:8}}>{l.date}</div>
                </div>
              ))
            }
          </div>
        </div>

        {/* Brand table */}
        <div style={S.card}>
          <div style={{fontSize:11,color:"#555",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:14}}>Brand Coverage</div>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
            <thead>
              <tr>
                {["Brand","Products w/ Issues","Active Total","Worked Today","This Week"].map(h => (
                  <th key={h} style={{padding:"8px 12px",textAlign:"left",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.5px",color:"#555",borderBottom:"1px solid #1a1a1a"}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {brandRows.map(r => (
                <tr key={r.vendor}>
                  <td style={{padding:"9px 12px",fontWeight:600}}>{r.vendor}</td>
                  <td style={{padding:"9px 12px",color:"#C0392B"}}>{r.issues.toLocaleString()}</td>
                  <td style={{padding:"9px 12px",color:"#666"}}>{r.total.toLocaleString()}</td>
                  <td style={{padding:"9px 12px"}}>
                    {r.todayWorkers.length > 0
                      ? r.todayWorkers.map(w => (
                          <span key={w} style={{background:"rgba(74,222,128,0.1)",color:"#4ade80",fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:20,marginRight:3}}>
                            {w.split(" ")[0]}
                          </span>
                        ))
                      : <span style={{color:"#333"}}>-</span>}
                  </td>
                  <td style={{padding:"9px 12px",color:r.weekCount>0?"#60A5FA":"#333"}}>
                    {r.weekCount > 0 ? `${r.weekCount} sessions` : "-"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ── shared components ─────────────────────────────────────────────────────────
function Bar({ user, vendor, onLogout, onManager }) {
  return (
    <div style={{background:"#000",borderBottom:"1px solid #1a1a1a",padding:"0 24px",height:52,display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:100}}>
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        <span style={{color:"#D4AF37",fontWeight:700,fontSize:15}}>Al Rugaib</span>
        <span style={{width:1,height:14,background:"#333"}}/>
        <span style={{fontSize:11,color:"#555",textTransform:"uppercase",letterSpacing:1}}>SEO Tracker</span>
        {vendor && <><span style={{width:1,height:14,background:"#333"}}/><span style={{fontSize:12,color:"#888"}}>{vendor}</span></>}
      </div>
      <div style={{display:"flex",alignItems:"center",gap:8,fontSize:12}}>
        <span style={{color:"#D4AF37",fontWeight:600}}>{user}</span>
        <button style={S.btnTiny} onClick={onManager}>Manager</button>
        <button style={S.btnTiny} onClick={onLogout}>Switch</button>
      </div>
    </div>
  );
}

